    let ttsText = userName 
      ? `Powered by Zanta X M D Mini. This song requested by ${userName.replace(/@/g, '')}` 
      : "Powered by Zanta X M D Mini";

    const ttsUrl = `https://api.bk9.dev/tools/tts?q=${encodeURIComponent(ttsText)}&lang=en`;
